import { ParserRegistry } from '../core/parser-registry';
import { getConnectorMark } from './connector-helpers'

export function _connectorMark(data, phase, condition) {
    let _this = this;
    let KEY = 'dependency';
    let _connectorG = {
        mark: 'g',
        selector: '.dependencySeries',
        data: [data.data],
        children: []
    };

    if(condition) {
        let options = this.builderC.commonPlotOptions[KEY];
        let connectorMark = getConnectorMark.call(this, options, KEY);
        _connectorG.children.push(connectorMark);
    }

    return _connectorG;
}


ParserRegistry.marks('gantt.connector', _connectorMark);



